import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Unified Analytics","description":"","frontmatter":{"title":"Unified Analytics","slug":"unified-analytics"},"headers":[],"relativePath":"marketer-hub/unified-analytics.md","filePath":"marketer-hub/unified-analytics.md"}'),o={name:"marketer-hub/unified-analytics.md"};function n(s,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Unified Analytics is part of the legacy Branch experience.</p><p>Our new Branch Analysis tool offers customizable dashboards made up of flexible widgets to capture the data you need. Branch Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, discover how to filter, share, and export campaign performance across different channels on our <a href="https://help.branch.io/docs/branch-analysis" target="_blank" rel="noreferrer">Analysis Overview</a> page.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Unified Analytics</strong> is a <a href="https://branch.dashboard.branch.io/ads/analytics/unified" target="_blank" rel="noreferrer">tab</a> of the <strong>Ads</strong> section of the Branch Dashboard where campaign data from all attribution methods (SKAdNetwork, <a href="./predictive-aggregate-measurement.html">PAM</a>, IDFA, IDFV, Apple Ads, and Android) are merged in a single view after removing duplicate SKAdNetwork data.</p><p>With Unified Analytics you will have an easier way to view data on a single report. Other features of Unified Analytics include:</p><ul><li>Corrected attribution for users who were flagged as organic who should have been attributed to non-organic media.</li><li>Ability to flag duplicated SKAN installs with a toggle.</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Unified Analytics, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Ads for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="./skadnetwork.html">Implemented SKAdNetwork</a>.</p></li></ol><h2 id="overview-table" tabindex="-1">Overview Table <a class="header-anchor" href="#overview-table" aria-label="Permalink to &quot;Overview Table&quot;">​</a></h2><p>The <strong>Overview</strong> <a href="https://dashboard.branch.io/ads/analytics/unified" target="_blank" rel="noreferrer">table</a> will be the main area for analyzing your campaign performance. Here you will be able to apply certain filters and add dimensions so you and your teams have a full understanding of your marketing efforts across mobile.</p><p>Note: Custom Events are <strong>not</strong> supported in Unified Analytics.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="compare-by-filter" tabindex="-1">Compare By &amp; Filter <a class="header-anchor" href="#compare-by-filter" aria-label="Permalink to &quot;Compare By &amp; Filter&quot;">​</a></h3><p>With Unified Analytics, you have the following dimensions to break your report out:</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Description</th></tr></thead><tbody><tr><td>ad partner</td><td>Ad partner of last touch – this is set automatically to be the name of the ad partner</td></tr><tr><td>ad partner (3p)</td><td>Ad partner (3p) of last touch – this is set automatically to be the 3p value of the ad partner</td></tr><tr><td>campaign</td><td>Campaign of last touch – this can be set as a custom analytics tag, or set automatically by ad networks like Facebook</td></tr><tr><td>campaign id</td><td>Campaign id of last touch – this is set automatically by ad networks like Facebook, or can be set with analytics tags on a link</td></tr><tr><td>platform</td><td>Platform (web vs app, desktop vs mobile) on which the event took place</td></tr><tr><td>attributed</td><td>Whether the event was attributed to any touch (click or impression) as opposed to unattributed (attributed: false). Unattributed data is the same as &quot;organic&quot; or &quot;direct&quot; data.</td></tr><tr><td>day</td><td>Break down metrics by day.</td></tr><tr><td>month</td><td>Break down metrics by month.</td></tr><tr><td>week</td><td>Break down metrics by week.</td></tr></tbody></table><h3 id="toggles" tabindex="-1">Toggles <a class="header-anchor" href="#toggles" aria-label="Permalink to &quot;Toggles&quot;">​</a></h3><p>In the Overview table, you can toggle certain checkboxes to enable the following:</p><table tabindex="0"><thead><tr><th>Toggle</th><th>Description</th></tr></thead><tbody><tr><td>Split SKAN Data</td><td>Enable this to view event counts from both SKAN and non-SKAN sources. Your report will now split events by the following: - <strong>Non-SKAN</strong> (de-duplicated from SKAN): - Event counts attributed using Device ID matching - Event counts attributed via <a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a>, not using Device ID matching - <strong>SKAN</strong> (de-duplicated from non-SKAN): - Event counts attributed only via SKAN methodology - <strong>Total</strong>: Arithmetic sum of SKAN and non-SKAN columns</td></tr><tr><td>Organic</td><td>When &quot;Organic&quot; is checked, unattributed data will show (attributed: false). This data is not attributed to any click or impression, and is the same as &quot;organic&quot; or &quot;direct&quot; data.</td></tr><tr><td>Unique</td><td>When &quot;Unique&quot; is checked, these are unique to a user. For example: if 1 user clicks 100 times, it will count as 1. There is no concept of &quot;unique revenue&quot;; &quot;revenue&quot; is always the sum of all purchase events.</td></tr></tbody></table><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="how-does-the-deduplication-work" tabindex="-1">How does the deduplication work? <a class="header-anchor" href="#how-does-the-deduplication-work" aria-label="Permalink to &quot;How does the deduplication work?&quot;">​</a></h4><p>The deduplication method is handled by Branch&#39;s servers and it does not involve complex conversion value mapping to occur. Unified Analytics aggregates the aggregate SKAN data with the device-level attribution data that is captured from multiple sources:</p><ul><li>Valid SKAdNetwork messages</li><li>Branch&#39;s Event Ontology topics</li><li>Other internal topics</li></ul><p>Branch uses these data points and deduplicates based on the device&#39;s app version and time lapsed between an install and an event.</p>',23)])])}const b=t(o,[["render",n]]);export{p as __pageData,b as default};
